import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  CcdcInventoryDto,
  CcdcTransactionDto,
  CreateCcdcEntryDto,
  CreateCcdcIssueDto,
  UpdateCcdcEntryDto,
  UpdateCcdcIssueDto,
} from './models';

const BASE = '/ccdc';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

async function getList<T>(path: string, params?: Record<string, string | number | boolean | undefined>): Promise<T[]> {
  const qs = params ? buildQs(params) : '';
  const res = await apiClient.get<BffResponse<T[]>>(`${path}${qs ? `?${qs}` : ''}`);
  return unwrap(res) ?? [];
}

export const ccdcEndpoint = {
  getInventory: (params?: Record<string, string | number | boolean | undefined>) =>
    getList<CcdcInventoryDto>(`${BASE}/inventory`, params),

  getTransactions: (params?: Record<string, string | number | boolean | undefined>) =>
    getList<CcdcTransactionDto>(`${BASE}/transactions`, params),

  createEntry: async (dto: CreateCcdcEntryDto) => {
    const res = await apiClient.post<BffResponse<CcdcTransactionDto>>(`${BASE}/transactions/entry`, dto);
    return unwrap(res);
  },

  createIssue: async (dto: CreateCcdcIssueDto) => {
    const res = await apiClient.post<BffResponse<CcdcTransactionDto>>(`${BASE}/transactions/issue`, dto);
    return unwrap(res);
  },

  updateEntry: async (id: string, dto: UpdateCcdcEntryDto) => {
    const res = await apiClient.put<BffResponse<CcdcTransactionDto>>(`${BASE}/transactions/entry/${id}`, dto);
    return unwrap(res);
  },

  updateIssue: async (id: string, dto: UpdateCcdcIssueDto) => {
    const res = await apiClient.put<BffResponse<CcdcTransactionDto>>(`${BASE}/transactions/issue/${id}`, dto);
    return unwrap(res);
  },
};

export const ccdcService = { ...ccdcEndpoint };
