import React, { useState, useMemo, useCallback } from 'react';
import {
  Button,
  Input,
  SearchTextInput,
  Select,
  Modal,
  Tabs,
  MoneyInput, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
  LinPageLayout,
  type Tab,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { ccdcService } from '../../../services/ccdc/ccdcService';
import {
  exportCcdcEntryCsv,
  exportCcdcInventoryCsv,
  exportCcdcIssueCsv,
} from '../../../services/ccdc/ccdcExport';
import type { CcdcInventoryDto, CcdcTransactionDto } from '../../../services/ccdc/models';
import { masterService } from '../../../services/master/masterService';
import type { DepartmentDto, ToolsEquipmentDto } from '../../../services/master/models';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {
  CatalogCompanyTh,
  CatalogCompanyTd,
  CatalogCompanyField,
  CatalogListPageTabs,
  CatalogListPagination,
  useCatalogPagination,
  useCatalogTableBusy,
  CatalogListGrid,
  CatalogListMasterListFooter,
  CatalogListExportButton,
  CatalogListToolbar,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-ccdc-quan-ly';

type TabId = 'inventory' | 'entry' | 'issue';

const PAGE_TABS: Tab[] = [
  { id: 'inventory', label: 'Tồn kho' },
  { id: 'entry', label: 'Nhập CCDC' },
  { id: 'issue', label: 'Cấp phát' },
];

type EntryFormErrors = Partial<Record<'toolsEquipmentId' | 'transactionDate' | 'quantity', string>>;
type IssueFormErrors = Partial<Record<'toolsEquipmentId' | 'transactionDate' | 'quantity', string>>;

const todayInputDate = () => new Date().toISOString().slice(0, 10);

const toDateInputValue = (iso: string) => (iso.includes('T') ? iso.slice(0, 10) : iso.slice(0, 10));

type EntryFormState = {
  toolsEquipmentId: string;
  transactionDate: string;
  quantity: string;
  unitPrice?: number;
  voucherNumber: string;
  supplierName: string;
  note: string;
};

type IssueFormState = {
  toolsEquipmentId: string;
  transactionDate: string;
  quantity: string;
  unitPrice?: number;
  deptCode: string;
  note: string;
};

const EMPTY_ENTRY_FORM: EntryFormState = {
  toolsEquipmentId: '', transactionDate: '', quantity: '', unitPrice: undefined, voucherNumber: '', supplierName: '', note: '',
};
const emptyEntryForm = (): EntryFormState => ({ ...EMPTY_ENTRY_FORM, transactionDate: todayInputDate() });
const EMPTY_ISSUE_FORM: IssueFormState = {
  toolsEquipmentId: '', transactionDate: '', quantity: '', unitPrice: undefined, deptCode: '', note: '',
};
const emptyIssueForm = (): IssueFormState => ({ ...EMPTY_ISSUE_FORM, transactionDate: todayInputDate() });

const cell = (v: unknown) => {
  if (v == null || v === '') return '—';
  return String(v);
};

const CcdcQuanLyPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);

  const [tab, setTab] = useState<TabId>('inventory');
  const [inventory, setInventory] = useState<CcdcInventoryDto[]>([]);
  const [entries, setEntries] = useState<CcdcTransactionDto[]>([]);
  const [issues, setIssues] = useState<CcdcTransactionDto[]>([]);
  const [ccdcList, setCcdcList] = useState<ToolsEquipmentDto[]>([]);
  const [departments, setDepartments] = useState<DepartmentDto[]>([]);
  const sessionCompanyName = useMemo(() => ccdcList[0]?.companyName ?? inventory[0]?.companyName, [ccdcList, inventory]);

  const [invSearchDraft, setInvSearchDraft] = useState('');
  const [invSearch, setInvSearch] = useState('');
  const [invDeptDraft, setInvDeptDraft] = useState('');
  const [invDept, setInvDept] = useState('');
  const [txnSearchDraft, setTxnSearchDraft] = useState('');
  const [txnSearch, setTxnSearch] = useState('');

  const [loading, setLoading] = useState(false);
  const [entryModalOpen, setEntryModalOpen] = useState(false);
  const [issueModalOpen, setIssueModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<CcdcTransactionDto | null>(null);
  const [editingIssue, setEditingIssue] = useState<CcdcTransactionDto | null>(null);
  const [entryForm, setEntryForm] = useState(EMPTY_ENTRY_FORM);
  const [issueForm, setIssueForm] = useState(EMPTY_ISSUE_FORM);
  const [entryErrors, setEntryErrors] = useState<EntryFormErrors>({});
  const [issueErrors, setIssueErrors] = useState<IssueFormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);

  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const {
    page: invPage,
    setPage: setInvPage,
    pageItems: pagedInventory,
    totalCount: invTotalCount,
    pageSize: invPageSize,
    setPageSize: setInvPageSize,
    resetPage: resetInvPage,
  } = useCatalogPagination(inventory);

  const {
    page: entryPage,
    setPage: setEntryPage,
    pageItems: pagedEntries,
    totalCount: entryTotalCount,
    pageSize: entryPageSize,
    setPageSize: setEntryPageSize,
    resetPage: resetEntryPage,
  } = useCatalogPagination(entries);

  const {
    page: issuePage,
    setPage: setIssuePage,
    pageItems: pagedIssues,
    totalCount: issueTotalCount,
    pageSize: issuePageSize,
    setPageSize: setIssuePageSize,
    resetPage: resetIssuePage,
  } = useCatalogPagination(issues);

  const inventorySelection = useCatalogListSelection({
    rows: pagedInventory,
    totalCount: invTotalCount,
    page: invPage,
    pageSize: invPageSize,
    getRowId: r => r.id,
    isRowSelectable: () => false,
  });

  const refresh = () => {
    inventorySelection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const handleInvSearch = () => {
    pulseSearch(() => {
      setInvSearch(invSearchDraft.trim());
      setInvDept(invDeptDraft);
      resetInvPage();
      inventorySelection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const handleInventoryBatchDelete = async (_mode: CatalogBatchDeleteMode) => {
    throw new Error('Tồn kho CCDC chỉ xem — không xóa');
  };

  const handleTxnSearch = () => {
    pulseSearch(() => {
      setTxnSearch(txnSearchDraft.trim());
      if (tab === 'entry') resetEntryPage();
      if (tab === 'issue') resetIssuePage();
      setReloadKey(k => k + 1);
    });
  };

  const closeEntryModal = useCallback(() => {
    guardedNavigate(() => {
      setEntryModalOpen(false);
      setEditingEntry(null);
      setEntryForm(EMPTY_ENTRY_FORM);
      setEntryErrors({});
      markClean();
    });
  }, [guardedNavigate, markClean]);

  const closeIssueModal = useCallback(() => {
    guardedNavigate(() => {
      setIssueModalOpen(false);
      setEditingIssue(null);
      setIssueForm(EMPTY_ISSUE_FORM);
      setIssueErrors({});
      markClean();
    });
  }, [guardedNavigate, markClean]);

  const handleTabChange = (id: string) => {
    const next = id as TabId;
    if (entryModalOpen || issueModalOpen) {
      guardedNavigate(() => {
        markClean();
        setEntryModalOpen(false);
        setIssueModalOpen(false);
        setEditingEntry(null);
        setEditingIssue(null);
        setTab(next);
      });
      return;
    }
    setTab(next);
  };

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      Promise.all([
        masterService.getToolsEquipment({ showInactive: false, page: 1, pageSize: 500 }),
        masterService.getDepartments({ page: 1, pageSize: 500 }),
      ])
        .then(([tools, depts]) => {
          if (!cancelled) {
            setCcdcList(tools.items);
            setDepartments(depts.items.filter(d => d.isActive));
          }
        })
        .catch(() => { /* optional */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      const loadInventory = tab === 'inventory'
        ? ccdcService.getInventory({
          search: invSearch || undefined,
          dept: invDept || undefined,
        })
        : Promise.resolve([] as CcdcInventoryDto[]);
      const loadEntry = tab === 'entry'
        ? ccdcService.getTransactions({ type: 'Entry', search: txnSearch || undefined })
        : Promise.resolve([] as CcdcTransactionDto[]);
      const loadIssue = tab === 'issue'
        ? ccdcService.getTransactions({ type: 'Issue', search: txnSearch || undefined })
        : Promise.resolve([] as CcdcTransactionDto[]);
      Promise.all([loadInventory, loadEntry, loadIssue])
        .then(([inv, ent, iss]) => {
          if (!cancelled) {
            if (tab === 'inventory') setInventory(inv);
            if (tab === 'entry') setEntries(ent);
            if (tab === 'issue') setIssues(iss);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải dữ liệu CCDC', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [tab, reloadKey, invSearch, invDept, txnSearch, dispatch]);

  const ccdcOpts = useMemo(
    () => ccdcList.map(c => ({ value: c.id, label: `${c.code} — ${c.name}` })),
    [ccdcList],
  );

  const deptFilterOpts = useMemo(
    () => [
      { value: '', label: '— Tất cả đơn vị —' },
      ...departments.map(d => ({ value: d.code, label: `${d.code} — ${d.name}` })),
    ],
    [departments],
  );

  const deptFormOpts = useMemo(
    () => [
      { value: '', label: '— Chọn đơn vị —' },
      ...departments.map(d => ({ value: d.code, label: `${d.code} — ${d.name}` })),
    ],
    [departments],
  );

  const clearEntryFieldError = (key: keyof EntryFormErrors) => {
    setEntryErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const clearIssueFieldError = (key: keyof IssueFormErrors) => {
    setIssueErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validateEntry = (): EntryFormErrors => {
    const next: EntryFormErrors = {};
    if (!entryForm.toolsEquipmentId) next.toolsEquipmentId = 'Chọn CCDC';
    if (!entryForm.transactionDate?.trim()) next.transactionDate = 'Chọn ngày nhập';
    if (!entryForm.quantity?.trim() || Number(entryForm.quantity) <= 0) next.quantity = 'Nhập số lượng';
    return next;
  };

  const validateIssue = (): IssueFormErrors => {
    const next: IssueFormErrors = {};
    if (!issueForm.toolsEquipmentId) next.toolsEquipmentId = 'Chọn CCDC';
    if (!issueForm.transactionDate?.trim()) next.transactionDate = 'Chọn ngày cấp';
    if (!issueForm.quantity?.trim() || Number(issueForm.quantity) <= 0) next.quantity = 'Nhập số lượng';
    return next;
  };

  const resolveToolsEquipmentId = useCallback(
    (row: CcdcTransactionDto) =>
      row.toolsEquipmentId || ccdcList.find(c => c.code === row.ccdcCode)?.id || '',
    [ccdcList],
  );

  const rowToEntryForm = useCallback(
    (row: CcdcTransactionDto): EntryFormState => ({
      toolsEquipmentId: resolveToolsEquipmentId(row),
      transactionDate: toDateInputValue(row.transactionDate),
      quantity: String(row.quantity),
      unitPrice: row.unitPrice,
      voucherNumber: row.voucherNumber ?? '',
      supplierName: row.supplierName ?? '',
      note: row.note ?? '',
    }),
    [resolveToolsEquipmentId],
  );

  const rowToIssueForm = useCallback(
    (row: CcdcTransactionDto): IssueFormState => ({
      toolsEquipmentId: resolveToolsEquipmentId(row),
      transactionDate: toDateInputValue(row.transactionDate),
      quantity: String(row.quantity),
      unitPrice: row.unitPrice,
      deptCode: row.deptCode ?? '',
      note: row.note ?? '',
    }),
    [resolveToolsEquipmentId],
  );

  const openEntryModal = () => {
    setEditingEntry(null);
    setEntryForm(emptyEntryForm());
    setEntryErrors({});
    markClean();
    setEntryModalOpen(true);
  };

  const openEditEntry = (row: CcdcTransactionDto) => {
    setEditingEntry(row);
    setEntryForm(rowToEntryForm(row));
    setEntryErrors({});
    markClean();
    setEntryModalOpen(true);
  };

  const openIssueModal = () => {
    setEditingIssue(null);
    setIssueForm(emptyIssueForm());
    setIssueErrors({});
    markClean();
    setIssueModalOpen(true);
  };

  const openEditIssue = (row: CcdcTransactionDto) => {
    setEditingIssue(row);
    setIssueForm(rowToIssueForm(row));
    setIssueErrors({});
    markClean();
    setIssueModalOpen(true);
  };

  const handleSaveEntry = async () => {
    const nextErrors = validateEntry();
    if (Object.keys(nextErrors).length > 0) {
      setEntryErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    const payload = {
      toolsEquipmentId: entryForm.toolsEquipmentId,
      transactionDate: entryForm.transactionDate,
      quantity: Number(entryForm.quantity),
      unitPrice: (entryForm.unitPrice ?? 0) > 0 ? entryForm.unitPrice : undefined,
      voucherNumber: entryForm.voucherNumber || undefined,
      supplierName: entryForm.supplierName.trim() || undefined,
      note: entryForm.note || undefined,
    };
    setSaving(true);
    try {
      if (editingEntry) {
        await ccdcService.updateEntry(editingEntry.id, payload);
        dispatchAppToast(dispatch, { message: 'Cập nhật nhập CCDC thành công', type: 'success' });
      } else {
        await ccdcService.createEntry(payload);
        dispatchAppToast(dispatch, { message: 'Ghi nhận nhập CCDC thành công', type: 'success' });
      }
      setEntryModalOpen(false);
      setEditingEntry(null);
      setEntryForm(EMPTY_ENTRY_FORM);
      markClean();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleSaveIssue = async () => {
    const nextErrors = validateIssue();
    if (Object.keys(nextErrors).length > 0) {
      setIssueErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    const payload = {
      toolsEquipmentId: issueForm.toolsEquipmentId,
      transactionDate: issueForm.transactionDate,
      quantity: Number(issueForm.quantity),
      unitPrice: (issueForm.unitPrice ?? 0) > 0 ? issueForm.unitPrice : undefined,
      deptCode: issueForm.deptCode || undefined,
      note: issueForm.note || undefined,
    };
    setSaving(true);
    try {
      if (editingIssue) {
        await ccdcService.updateIssue(editingIssue.id, payload);
        dispatchAppToast(dispatch, { message: 'Cập nhật cấp phát CCDC thành công', type: 'success' });
      } else {
        await ccdcService.createIssue(payload);
        dispatchAppToast(dispatch, { message: 'Ghi nhận cấp phát CCDC thành công', type: 'success' });
      }
      setIssueModalOpen(false);
      setEditingIssue(null);
      setIssueForm(EMPTY_ISSUE_FORM);
      markClean();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const listTitle =
    tab === 'inventory' ? 'Tồn kho CCDC' : tab === 'entry' ? 'Danh sách nhập CCDC' : 'Danh sách cấp phát CCDC';

  const emptyMessage = () => {
    if (tab === 'inventory' && (invSearch || invDept)) return 'Không tìm thấy CCDC phù hợp';
    if ((tab === 'entry' || tab === 'issue') && txnSearch) return 'Không tìm thấy phiếu phù hợp';
    return 'Không có dữ liệu';
  };

  const renderInventoryGrid = (rows: CcdcInventoryDto[]) => (
    <CatalogListGrid
      testIdPrefix={TEST_ID}
      rows={rows}
      page={invPage}
      pageSize={invPageSize}
      selection={inventorySelection}
      getRowId={r => r.id}
      isRowSelectable={() => false}
      headerCells={(
        <>
          <th>Mã</th>
          <th>Tên</th>
          <CatalogCompanyTh />
          <th>Đơn vị</th>
          <th>SL</th>
          <th className={styles.colRight}>Đơn giá</th>
          <th>Ngày cấp</th>
        </>
      )}
      renderRow={r => (
        <>
          <td><code>{cell(r.code)}</code></td>
          <td>{cell(r.name)}</td>
          <CatalogCompanyTd label={r.companyName} />
          <td>{cell(r.deptName)}</td>
          <td>{cell(r.quantity)}</td>
          <td className={styles.colRight}>{r.unitPrice != null ? formatVnd(r.unitPrice) : '—'}</td>
          <td>{r.issueDate ? formatDate(r.issueDate) : '—'}</td>
        </>
      )}
    />
  );

  const renderTransactionsTable = (rows: CcdcTransactionDto[], txnTab: 'entry' | 'issue') => (
    <div className={styles.tableWrapper}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th>Ngày</th>
            <th>Số CT</th>
            <th>Mã CCDC</th>
            <th>Tên</th>
            <th>Nhà cung cấp</th>
            <th>SL</th>
            <th className={styles.colRight}>Đơn giá</th>
            {txnTab === 'issue' && <th>Đơn vị</th>}
            <th>Ghi chú</th>
            <th className={styles.colActions} />
          </tr>
        </thead>
        <tbody>
          {rows.map(r => (
            <tr key={r.id}>
              <td>{formatDate(r.transactionDate)}</td>
              <td>{cell(r.voucherNumber)}</td>
              <td><code>{cell(r.ccdcCode)}</code></td>
              <td>{cell(r.ccdcName)}</td>
              <td>{cell(r.supplierName)}</td>
              <td>{cell(r.quantity)}</td>
              <td className={styles.colRight}>{r.unitPrice != null ? formatVnd(r.unitPrice) : '—'}</td>
              {txnTab === 'issue' && <td>{cell(r.deptName ?? r.deptCode)}</td>}
              <td>{cell(r.note)}</td>
              <td className={styles.colActions}>
                <button
                  type="button"
                  className={styles.actionBtn}
                  onClick={() => (txnTab === 'entry' ? openEditEntry(r) : openEditIssue(r))}
                  title="Sửa"
                  data-testid={`${TEST_ID}-edit-${txnTab}-${r.id}`}
                >
                  <i className="fas fa-edit" />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const currentRows =
    tab === 'inventory' ? pagedInventory : tab === 'entry' ? pagedEntries : pagedIssues;
  const currentTotal =
    tab === 'inventory' ? invTotalCount : tab === 'entry' ? entryTotalCount : issueTotalCount;

  const tabsNode = (
    <CatalogListPageTabs data-testid={`${TEST_ID}-tabs`}>
      <Tabs tabs={PAGE_TABS} activeTab={tab} onTabChange={handleTabChange} variant="underline" />
    </CatalogListPageTabs>
  );

  const pageHeader = {
    title: 'Quản lý CCDC',
    titleIconClass: 'fas fa-clipboard-list',
  };

  const listBody = !showTableLoading && currentRows.length === 0 ? (
    <div className={styles.empty}>
      <i className="fas fa-inbox" />
      <p>{emptyMessage()}</p>
    </div>
  ) : tab === 'inventory' ? (
    renderInventoryGrid(currentRows as CcdcInventoryDto[])
  ) : tab === 'entry' ? (
    renderTransactionsTable(currentRows as CcdcTransactionDto[], 'entry')
  ) : (
    renderTransactionsTable(currentRows as CcdcTransactionDto[], 'issue')
  );

  const filterContent = tab === 'inventory' ? (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Tìm mã, tên CCDC..."
          value={invSearchDraft}
          onChange={setInvSearchDraft}
          onSearch={handleInvSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </div>
      <div className={styles.field} data-testid={`${TEST_ID}-field-dept-filter`}>
        <Select
          value={invDeptDraft}
          className={selectPlaceholderClass(invDeptDraft)}
          onChange={e => setInvDeptDraft(e.target.value)}
          options={deptFilterOpts}
        />
      </div>
    </>
  ) : (
    <div className={styles.field} data-testid={`${TEST_ID}-field-txn-search`}>
      <SearchTextInput
        label="Tìm kiếm"
        placeholder="Tìm mã, tên CCDC..."
        value={txnSearchDraft}
        onChange={setTxnSearchDraft}
        onSearch={handleTxnSearch}
        testId={`${TEST_ID}-txn-search-text`}
      />
    </div>
  );

  const handleExport = async () => {
    if (tab === 'inventory') exportCcdcInventoryCsv(inventory);
    else if (tab === 'entry') exportCcdcEntryCsv(entries);
    else exportCcdcIssueCsv(issues);
  };

  const exportButton = (
    <CatalogListExportButton testIdPrefix={TEST_ID} onExport={handleExport} />
  );

  const listFooter = !showTableLoading && currentTotal > 0 ? (
    tab === 'inventory' ? (
      <CatalogListMasterListFooter
        testIdPrefix={TEST_ID}
        page={invPage}
        totalCount={invTotalCount}
        pageSize={invPageSize}
        onPageChange={p => { setInvPage(p); inventorySelection.clearSelection(); }}
        onPageSizeChange={setInvPageSize}
      />
    ) : tab === 'entry' ? (
      <CatalogListPagination
        testIdPrefix={`${TEST_ID}-entry`}
        page={entryPage}
        totalCount={entryTotalCount}
        pageSize={entryPageSize}
        onPageChange={setEntryPage}
        onPageSizeChange={setEntryPageSize}
      />
    ) : (
      <CatalogListPagination
        testIdPrefix={`${TEST_ID}-issue`}
        page={issuePage}
        totalCount={issueTotalCount}
        pageSize={issuePageSize}
        onPageChange={setIssuePage}
        onPageSizeChange={setIssuePageSize}
      />
    )
  ) : undefined;

  return (
    <>
    {tab === 'inventory' ? (
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        selection={inventorySelection}
        totalCount={invTotalCount}
        selectableOnPage={[]}
        canAdd={false}
        onAdd={() => {}}
        onEdit={() => {}}
        onRefresh={refresh}
        toolbarExtraLeftActions={exportButton}
        onBatchDelete={handleInventoryBatchDelete}
        page={invPage}
        pageSize={invPageSize}
        onPageChange={p => { setInvPage(p); inventorySelection.clearSelection(); }}
        onPageSizeChange={setInvPageSize}
        showTableLoading={showTableLoading}
        header={pageHeader}
        listTitle={listTitle}
        beforeToolbarExtra={tabsNode}
        filters={filterContent}
        filtersTestId={`${TEST_ID}-filters-${tab}`}
        useCatalogToolbarPreset
      >
        {listBody}
      </CatalogListMasterLinPageLayout>
    ) : (
      <div className={styles.catalogListRoot} data-catalog-list-page data-testid={`${TEST_ID}-list`}>
        <LinPageLayout
          kind="catalog"
          testIdPrefix={TEST_ID}
          pageClassName={styles.catalogListPage}
          header={pageHeader}
          beforeToolbar={tabsNode}
          toolbar={(
            <CatalogListToolbar
              testIdPrefix={TEST_ID}
              canAdd
              onAdd={tab === 'entry' ? openEntryModal : openIssueModal}
              onRefresh={refresh}
              extraLeftActions={exportButton}
            />
          )}
          listTitle={listTitle}
          filtersTestId={`${TEST_ID}-filters-${tab}`}
          showTableLoading={showTableLoading}
          footer={listFooter}
          filters={filterContent}
        >
          {listBody}
        </LinPageLayout>
      </div>
    )}

      <Modal
        isOpen={entryModalOpen}
        onClose={closeEntryModal}
        title={editingEntry ? 'Sửa nhập CCDC' : 'Nhập CCDC'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form-entry`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-toolsEquipmentId`}>
              <label className={styles.label}>CCDC *</label>
              <Select
                value={entryForm.toolsEquipmentId}
                error={entryErrors.toolsEquipmentId}
                placeholder="— Chọn CCDC —"
                className={selectPlaceholderClass(entryForm.toolsEquipmentId)}
                disabled={!!editingEntry}
                onChange={e => {
                  clearEntryFieldError('toolsEquipmentId');
                  markDirty();
                  setEntryForm(f => ({ ...f, toolsEquipmentId: e.target.value }));
                }}
                options={ccdcOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-transactionDate`}>
              <label className={styles.label}>Ngày nhập *</label>
              <Input
                type="date"
                value={entryForm.transactionDate}
                error={entryErrors.transactionDate}
                onChange={e => {
                  clearEntryFieldError('transactionDate');
                  markDirty();
                  setEntryForm(f => ({ ...f, transactionDate: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-quantity`}>
              <label className={styles.label}>Số lượng *</label>
              <Input
                type="number"
                value={entryForm.quantity}
                error={entryErrors.quantity}
                onChange={e => {
                  clearEntryFieldError('quantity');
                  markDirty();
                  setEntryForm(f => ({ ...f, quantity: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-unitPrice`}>
              <label className={styles.label}>Đơn giá</label>
              <MoneyInput
                value={entryForm.unitPrice ?? 0}
                onChange={v => {
                  markDirty();
                  setEntryForm(f => ({ ...f, unitPrice: v }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-voucherNumber`}>
              <label className={styles.label}>Số chứng từ</label>
              <Input
                value={entryForm.voucherNumber}
                onChange={e => {
                  markDirty();
                  setEntryForm(f => ({ ...f, voucherNumber: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-supplierName`}>
              <label className={styles.label}>Nhà cung cấp</label>
              <Input
                value={entryForm.supplierName}
                onChange={e => {
                  markDirty();
                  setEntryForm(f => ({ ...f, supplierName: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-note`}>
              <label className={styles.label}>Ghi chú</label>
              <Input
                value={entryForm.note}
                onChange={e => {
                  markDirty();
                  setEntryForm(f => ({ ...f, note: e.target.value }));
                }}
              />
            </div>
          </div>
          <CatalogCompanyField testIdPrefix={TEST_ID} companyName={sessionCompanyName} />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={closeEntryModal}>Hủy</Button>
            <Button variant="primary" onClick={handleSaveEntry} disabled={saving} data-testid={`${TEST_ID}-save-entry-btn`}>
              {saving ? 'Đang lưu...' : editingEntry ? 'Cập nhật' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>

      <Modal
        isOpen={issueModalOpen}
        onClose={closeIssueModal}
        title={editingIssue ? 'Sửa cấp phát CCDC' : 'Cấp phát CCDC'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form-issue`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueToolsEquipmentId`}>
              <label className={styles.label}>CCDC *</label>
              <Select
                value={issueForm.toolsEquipmentId}
                error={issueErrors.toolsEquipmentId}
                placeholder="— Chọn CCDC —"
                className={selectPlaceholderClass(issueForm.toolsEquipmentId)}
                disabled={!!editingIssue}
                onChange={e => {
                  clearIssueFieldError('toolsEquipmentId');
                  markDirty();
                  setIssueForm(f => ({ ...f, toolsEquipmentId: e.target.value }));
                }}
                options={ccdcOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueTransactionDate`}>
              <label className={styles.label}>Ngày cấp *</label>
              <Input
                type="date"
                value={issueForm.transactionDate}
                error={issueErrors.transactionDate}
                onChange={e => {
                  clearIssueFieldError('transactionDate');
                  markDirty();
                  setIssueForm(f => ({ ...f, transactionDate: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueQuantity`}>
              <label className={styles.label}>Số lượng *</label>
              <Input
                type="number"
                value={issueForm.quantity}
                error={issueErrors.quantity}
                onChange={e => {
                  clearIssueFieldError('quantity');
                  markDirty();
                  setIssueForm(f => ({ ...f, quantity: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueUnitPrice`}>
              <label className={styles.label}>Đơn giá</label>
              <MoneyInput
                value={issueForm.unitPrice ?? 0}
                onChange={v => {
                  markDirty();
                  setIssueForm(f => ({ ...f, unitPrice: v }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-deptCode`}>
              <label className={styles.label}>Đơn vị nhận</label>
              <Select
                value={issueForm.deptCode}
                className={selectPlaceholderClass(issueForm.deptCode)}
                onChange={e => {
                  markDirty();
                  setIssueForm(f => ({ ...f, deptCode: e.target.value }));
                }}
                options={deptFormOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueNote`}>
              <label className={styles.label}>Ghi chú</label>
              <Input
                value={issueForm.note}
                onChange={e => {
                  markDirty();
                  setIssueForm(f => ({ ...f, note: e.target.value }));
                }}
              />
            </div>
          </div>
          <CatalogCompanyField testIdPrefix={TEST_ID} companyName={sessionCompanyName} />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={closeIssueModal}>Hủy</Button>
            <Button variant="primary" onClick={handleSaveIssue} disabled={saving} data-testid={`${TEST_ID}-save-issue-btn`}>
              {saving ? 'Đang lưu...' : editingIssue ? 'Cập nhật' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </>
  );
};

export default CcdcQuanLyPage;
