import { downloadCatalogCsv } from '../../utils/exportCatalogCsv';
import { formatDate, formatVnd } from '../../utils/formatters';
import type { CcdcInventoryDto, CcdcTransactionDto } from './models';

const stamp = () => new Date().toISOString().slice(0, 10);

export function exportCcdcInventoryCsv(rows: CcdcInventoryDto[]) {
  downloadCatalogCsv(
    `CcdcTonKho-${stamp()}`,
    ['Mã', 'Tên', 'Đơn vị', 'SL', 'Đơn giá', 'Ngày cấp'],
    rows.map(r => [
      r.code,
      r.name,
      r.deptName ?? '',
      r.quantity,
      r.unitPrice != null ? formatVnd(r.unitPrice) : '',
      r.issueDate ? formatDate(r.issueDate) : '',
    ]),
  );
}

export function exportCcdcEntryCsv(rows: CcdcTransactionDto[]) {
  downloadCatalogCsv(
    `CcdcNhap-${stamp()}`,
    ['Ngày', 'Số CT', 'Mã CCDC', 'Tên', 'Nhà cung cấp', 'SL', 'Đơn giá', 'Ghi chú'],
    rows.map(r => [
      formatDate(r.transactionDate),
      r.voucherNumber ?? '',
      r.ccdcCode,
      r.ccdcName,
      r.supplierName ?? '',
      r.quantity,
      r.unitPrice != null ? formatVnd(r.unitPrice) : '',
      r.note ?? '',
    ]),
  );
}

export function exportCcdcIssueCsv(rows: CcdcTransactionDto[]) {
  downloadCatalogCsv(
    `CcdcCapPhat-${stamp()}`,
    ['Ngày', 'Mã CCDC', 'Tên', 'SL', 'Đơn giá', 'Đơn vị', 'Ghi chú'],
    rows.map(r => [
      formatDate(r.transactionDate),
      r.ccdcCode,
      r.ccdcName,
      r.quantity,
      r.unitPrice != null ? formatVnd(r.unitPrice) : '',
      r.deptName ?? r.deptCode ?? '',
      r.note ?? '',
    ]),
  );
}
